/**
 * fetchModel - Fetch a model from the web server.
 * @param {string} url - The URL to fetch.
 * @returns {Promise} - A promise that resolves with the fetched model or rejects with an error.
 */
function fetchModel(url) {
  return new Promise(function (resolve, reject) {
    fetch(url)
      .then((response) => {
        if (!response.ok) {
          // Trả về lỗi nếu status code không phải 200-299
          return response.text().then((text) => reject({ status: response.status, message: text }));
        }
        return response.json(); // Giải mã dữ liệu JSON
      })
      .then((data) => resolve({ data: data }))
      .catch((error) => reject({ status: 500, message: error.message }));
  });
}

export default fetchModel;
